+struct TempRestoreGuard {
+    path: PathBuf,
+    persist: bool,
+}
+
+impl TempRestoreGuard {
+    fn new(path: PathBuf) -> Self {
+        Self {
+            path,
+            persist: false,
+        }
+    }
+
+    fn persist(&mut self) {
+        self.persist = true;
+    }
+}
+
+impl Drop for TempRestoreGuard {
+    fn drop(&mut self) {
+        if !self.persist && self.path.exists() {
+            let _ = fs::remove_file(&self.path);
+        }
+    }
+}
